  private buildMessages(
    plan: GenerateTextArgs['plan'],
    userMessage: string,
    providerOptions?: Record<string, unknown>,
    ttl?: '5m' | '1h',
  ): Anthropic.MessageParam[] {
    const override = providerOptions?.messages as
      | Array<{ role: string; content: unknown }>
      | undefined;
