      const minTokens = anthropicCacheMinTokens(plan.routeId);
      const prefixText = filtered
        .slice(0, -1)
        .map((m) =>
          Array.isArray(m.content)
            ? m.content
                .map((part) => ('text' in part ? String(part.text ?? '') : ''))
