    if (!apiKey && !this.serviceAccountJson) {
      throw new Error(
        'GoogleGeminiAdapter: GEMINI_API_KEY or GOOGLE_APPLICATION_CREDENTIALS_JSON is not set. Set one for google/* routes.',
