      : await this.generateContentWithOAuth({
          modelId: route.modelId,
          contents,
          systemPrompt,
          generationConfig,
        });

    return {
      text: extractTextFromGeminiResponse(response),
      usage: normalizeGeminiUsage(response, Date.now() - callStartedAt),
      rawResponse: response,
    };
