  const parts: string[] = [];
  for (const chunk of chunks) {
    const header = `DOCUMENT CHUNK\nDocument Chunk ID: ${chunk.id}\nContent:\n`;
    const footer = '\n---\n';
    parts.push(`${header}${chunk.text}${footer}`);
