          value={formatPct(summary?.avg_cache_hit_ratio_7d ?? null)}
          subtitle="Average across all routes"
          trend={(summary?.avg_cache_hit_ratio_7d ?? 0) >= 0.5 ? 'up' : 'down'}
        />
