import { z } from 'zod';

function assert(cond: unknown, msg: string): asserts cond {
  if (!cond) {
    console.error(`x ${msg}`);
    process.exit(1);
  }
  console.log(`ok ${msg}`);
}

function route(provider: 'openai' | 'qwen', modelId: string): OracleModelRoute {
  return {
    routeId: `${provider}/${modelId}`,
    role: 'interview',
    tier: 'primary',
    internalPurpose: null,
    provider,
    modelId,
    displayName: modelId,
